package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.lang.reflect.Modifier;

public class CSVFormatTest {

    @Test
    public void testGetNullString_DefaultInstance() {
        CSVFormat format = CSVFormat.DEFAULT;
        // DEFAULT nullString is null
        assertNull(format.getNullString());
    }

    @Test
    public void testGetNullString_CustomNullString() throws Exception {
        // Create CSVFormat instance with reflection to set private final nullString field
        CSVFormat format = CSVFormat.DEFAULT;

        Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        nullStringField.setAccessible(true);

        // Remove final modifier from the field (works on Java 8 and below)
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(nullStringField, nullStringField.getModifiers() & ~Modifier.FINAL);

        // Set nullString to a custom value
        nullStringField.set(format, "NULL");

        assertEquals("NULL", format.getNullString());
    }

    @Test
    public void testGetNullString_WithNullStringViaWithNullString() {
        CSVFormat format = CSVFormat.DEFAULT.withNullString("N/A");
        assertEquals("N/A", format.getNullString());
    }

}
